// Creamos un array (lista) donde vamos a guardar los resultados finales
const itemsOut = [];

// Recorremos cada item que entra al nodo (n8n siempre trabaja con arrays)
for (const item of items) {

  // Tomamos el texto de la respuesta (si no existe, usamos string vacío)
  let text = item.json.output || "";

  // Limpiamos posibles bloques tipo ```json ``` que a veces devuelve la IA
  text = text.replace(/```json|```/g, "").trim();

  // Inicializamos el puntaje en 0
  let score = 0;

  // ================================
  // 1. VALIDAR ESTRUCTURA (vale 3 puntos)
  // ================================
  // Verificamos que estén TODAS las secciones obligatorias
  const hasStructure =
    text.includes("1. Respuesta breve:") &&
    text.includes("2. Explicación:") &&
    text.includes("3. Recomendación:") &&
    text.includes("4. Nivel de urgencia:") &&
    text.includes("5. Advertencia:");

  // Si cumple, sumamos 3 puntos
  if (hasStructure) score += 3;


  // ================================
  // 2. VALIDAR LONGITUD (vale 2 puntos)
  // ================================
  // Contamos la cantidad de caracteres del texto
  const length = text.length;

  // Si está entre 80 y 500 caracteres, sumamos 2 puntos
  if (length >= 80 && length <= 500) score += 2;


  // ================================
  // 3. VALIDAR NIVEL DE URGENCIA (vale 2 puntos)
  // ================================
  // Usamos una expresión regular para buscar:
  // "4. Nivel de urgencia: Bajo / Medio / Alto"
  const urgencyMatch = text.match(/4\. Nivel de urgencia:\s*(Bajo|Medio|Alto)/i);

  // Si encuentra uno válido, suma 2 puntos
  if (urgencyMatch) score += 2;


  // ================================
  // 4. EVITAR DIAGNÓSTICOS DIRECTOS (vale 1 punto)
  // ================================
  // Lista de palabras que NO queremos que aparezcan
  const forbiddenWords = ["tiene", "padece", "puede tener", "presenta"];

  // Revisamos si alguna de esas palabras está en el texto
  const hasForbidden = forbiddenWords.some(word =>
    text.toLowerCase().includes(word)
  );

  // Si NO hay palabras prohibidas, sumamos 1 punto
  if (!hasForbidden) score += 1;


  // ================================
  // 5. CALIDAD EXTRA (vale 2 puntos)
  // ================================
  // Dividimos el texto en secciones usando los números (1. 2. 3. ...)
  const sections = text.split(/\d\.\s/).slice(1);

  // Contador de secciones válidas
  let validSections = 0;

  // Recorremos cada sección
  for (const section of sections) {

    // Si la sección tiene más de 20 caracteres, la consideramos válida
    if (section.trim().length > 20) {
      validSections++;
    }
  }

  // Si las 5 secciones tienen contenido suficiente, sumamos 2 puntos
  if (validSections === 5) score += 2;


  // ================================
  // GUARDAMOS EL RESULTADO FINAL
  // ================================
  itemsOut.push({
    json: {
      score, // puntaje final
      length, // cantidad de caracteres
      structure_ok: hasStructure, // si cumple estructura
      urgency_ok: !!urgencyMatch, // si urgencia es válida
      no_diagnosis: !hasForbidden, // si evita diagnóstico
      valid_sections: validSections // cuántas secciones son buenas
    }
  });
}

// Devolvemos los resultados a n8n
return itemsOut;

// Esta línea obtiene un espacio de memoria "global"
// Es decir, datos que se guardan entre ejecuciones del workflow
// (como si fuera una cajita donde guardás cosas para reutilizar después)
const globalData = $getWorkflowStaticData('global');


// Acá verificamos si ya existe un contador llamado "retries"
// Si NO existe (por ejemplo, la primera vez que corre el flujo)
if (!globalData.retries) {

  // Entonces lo creamos y lo ponemos en 0
  // Esto es como decir: "arrancamos el contador desde cero"
  globalData.retries = 0;
}


// Acá aumentamos el contador en 1
// O sea: cada vez que pasa por este nodo, suma 1
globalData.retries += 1;


// Ahora devolvemos los datos del flujo (items)
// pero agregándole el valor actual de "retries" a cada uno
return items.map(item => ({
  json: {

    // Mantenemos toda la info original del item
    ...item.json,

    // Y le agregamos el número de intentos (retries)
    retries: globalData.retries
  }
}));

